1	// COR24 APL Interpreter -- Array Data Structure
2	// Bump-allocated heap with rank/shape headers.
3	// Supports rank 0 (scalar), rank 1 (vector), rank 2 (matrix).
4	//
5	// Heap layout per array:
6	//   [idx+0] = rank  (0, 1, or 2)
7	//   [idx+1] = dim0  (length for vectors, rows for matrices)
8	//   [idx+2] = dim1  (cols for matrices, 0 otherwise)
9	//   [idx+3] = type  (0=numeric, 1=character)
10	//   [idx+4..] = data elements
11	
12	#pragma once
13	
14	#define HEAP_SIZE 4096
15	#define ARR_HDR   4
16	
17	#define ARR_NUM   0
18	#define ARR_CHAR  1
19	
20	int heap[HEAP_SIZE];
21	int heap_top;
22	
23	// Reset heap (reclaim all arrays)
24	void arr_reset() {
25	    heap_top = 0;
26	}
27	
28	// Allocate array. Returns heap index, or -1 if full.
29	// For rank 0: dim0=1, dim1=0 (one scalar element)
30	// For rank 1: dim0=length, dim1=0
31	// For rank 2: dim0=rows, dim1=cols
32	int arr_new(int rank, int dim0, int dim1) {
33	    int size;
34	    if (rank <= 1) {
35	        size = dim0;
36	    } else {
37	        size = dim0 * dim1;
38	    }
39	    int need = ARR_HDR + size;
40	    if (heap_top + need > HEAP_SIZE) return -1;
41	
42	    int idx = heap_top;
43	    heap[idx]     = rank;
44	    heap[idx + 1] = dim0;
45	    heap[idx + 2] = dim1;
46	    heap[idx + 3] = ARR_NUM;
47	    heap_top = heap_top + need;
48	
49	    // Zero-fill data
50	    int i = 0;
51	    while (i < size) {
52	        heap[idx + ARR_HDR + i] = 0;
53	        i++;
54	    }
55	    return idx;
56	}
57	
58	// Accessors
59	int arr_rank(int idx) { return heap[idx]; }
60	int arr_dim0(int idx) { return heap[idx + 1]; }
61	int arr_dim1(int idx) { return heap[idx + 2]; }
62	int arr_type(int idx) { return heap[idx + 3]; }
63	void arr_set_type(int idx, int t) { heap[idx + 3] = t; }
64	
65	// Total element count
66	int arr_size(int idx) {
67	    if (heap[idx] <= 1) return heap[idx + 1];
68	    return heap[idx + 1] * heap[idx + 2];
69	}
70	
71	// Get/set data element by flat index
72	int arr_get(int idx, int i) {
73	    return heap[idx + ARR_HDR + i];
74	}
75	
76	void arr_set(int idx, int i, int val) {
77	    heap[idx + ARR_HDR + i] = val;
78	}
79	
80	// Create a scalar array holding one value
81	int arr_scalar(int val) {
82	    int idx = arr_new(0, 1, 0);
83	    if (idx < 0) return -1;
84	    arr_set(idx, 0, val);
85	    return idx;
86	}
87	
88	// Create a vector from inline values (up to count elements)
89	int arr_vector(int count) {
90	    return arr_new(1, count, 0);
91	}
