1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	#define NODE_QLED  10   // qled read (no children)
21	#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
22	#define NODE_QSW   12   // qsw read (no children, read-only)
23	#define NODE_QSVO  13   // shared variable offer (val = sym index, right = AP expr)
24	#define NODE_SVO_READ  14   // shared var indexed read (val = sym index, right = index expr)
25	#define NODE_SVO_WRITE 15  // shared var indexed write (val = sym index, left = index, right = value)
26	#define NODE_GOTO  16   // unconditional branch (right = target expr)
27	#define NODE_CGOTO 17   // conditional branch (left = cond, right = target)
28	#define NODE_FNCALL 18  // user function call (val = fn index, left = left arg/-1, right = right arg)
29	
30	#define AST_MAX 64
31	
32	// AST storage (parallel arrays)
33	int node_type[AST_MAX];
34	int node_val[AST_MAX];
35	int node_left[AST_MAX];
36	int node_right[AST_MAX];
37	int node_count;
38	
39	// Parser state
40	int parse_pos;
41	int parse_err;
42	char *parse_line;   // source line for identifier lookup
43	
44	// Allocate a new AST node
45	int ast_new() {
46	    if (node_count >= AST_MAX) {
47	        parse_err = 1;
48	        return 0;
49	    }
50	    int n = node_count;
51	    node_count++;
52	    node_left[n] = -1;
53	    node_right[n] = -1;
54	    return n;
55	}
56	
57	int ast_num(int val) {
58	    int n = ast_new();
59	    node_type[n] = NODE_NUM;
60	    node_val[n] = val;
61	    return n;
62	}
63	
64	int ast_binop(int op, int left, int right) {
65	    int n = ast_new();
66	    node_type[n] = NODE_BINOP;
67	    node_val[n] = op;
68	    node_left[n] = left;
69	    node_right[n] = right;
70	    return n;
71	}
72	
73	int ast_neg(int operand) {
74	    int n = ast_new();
75	    node_type[n] = NODE_NEG;
76	    node_right[n] = operand;
77	    return n;
78	}
79	
80	int ast_ident(int sym_idx) {
81	    int n = ast_new();
82	    node_type[n] = NODE_IDENT;
83	    node_val[n] = sym_idx;
84	    return n;
85	}
86	
87	int ast_assign(int sym_idx, int expr) {
88	    int n = ast_new();
89	    node_type[n] = NODE_ASSIGN;
90	    node_val[n] = sym_idx;
91	    node_right[n] = expr;
92	    return n;
93	}
94	
95	int ast_vec(int heap_idx) {
96	    int n = ast_new();
97	    node_type[n] = NODE_VEC;
98	    node_val[n] = heap_idx;
99	    return n;
100	}
101	
102	int ast_monad(int res_id, int operand) {
103	    int n = ast_new();
104	    node_type[n] = NODE_MONAD;
105	    node_val[n] = res_id;
106	    node_right[n] = operand;
107	    return n;
108	}
109	
110	int ast_dyad(int res_id, int left, int right) {
111	    int n = ast_new();
112	    node_type[n] = NODE_DYAD;
113	    node_val[n] = res_id;
114	    node_left[n] = left;
115	    node_right[n] = right;
116	    return n;
117	}
118	
119	int ast_reduce(int op, int operand) {
120	    int n = ast_new();
121	    node_type[n] = NODE_REDUCE;
122	    node_val[n] = op;
123	    node_right[n] = operand;
124	    return n;
125	}
126	
127	// Check if a reserved word can be used dyadically
128	int is_dyadic_res(int res_id) {
129	    return res_id == RES_RHO || res_id == RES_TAKE || res_id == RES_DROP || res_id == RES_CAT || res_id == RES_AND || res_id == RES_OR || res_id == RES_CEIL || res_id == RES_FLOOR || res_id == RES_COMPRESS;
130	}
131	
132	// Temporary buffer for collecting strand elements
133	int strand_buf[64];
134	
135	int is_binop(int ty) {
136	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH ||
137	           ty == TOK_EQ || ty == TOK_NE || ty == TOK_LT || ty == TOK_GT ||
138	           ty == TOK_LE || ty == TOK_GE;
139	}
140	
141	// Check if token at pos could start an expression (for function call detection)
142	int can_start_expr(int pos) {
143	    int ty = tok_type[pos];
144	    if (ty == TOK_NUM || ty == TOK_LPAREN || ty == TOK_IDENT ||
145	        ty == TOK_MINUS || ty == TOK_RES || ty == TOK_QLED || ty == TOK_QSW ||
146	        ty == TOK_STRING) return 1;
147	    if (is_binop(ty) && tok_type[pos + 1] == TOK_SLASH) return 1;  // reduce
148	    return 0;
149	}
150	
151	// Combined parse function avoids mutual recursion.
152	// mode 0 = expression, mode 1 = value only
153	int parse_node(int mode);
154	
155	int parse_node(int mode) {
156	    if (parse_err) return 0;
157	
158	    int left;
159	    int ty = tok_type[parse_pos];
160	
161	    // -- Parse a value --
162	
163	    if (ty == TOK_NUM) {
164	        left = ast_num(tok_val[parse_pos]);
165	        parse_pos++;
166	
167	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
168	        if (tok_type[parse_pos] == TOK_NUM) {
169	            strand_buf[0] = node_val[left];
170	            int count = 1;
171	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
172	                strand_buf[count] = tok_val[parse_pos];
173	                parse_pos++;
174	                count++;
175	            }
176	            int aidx = arr_vector(count);
177	            if (aidx < 0) { parse_err = 1; return 0; }
178	            int si = 0;
179	            while (si < count) {
180	                arr_set(aidx, si, strand_buf[si]);
181	                si++;
182	            }
183	            left = ast_vec(aidx);
184	        }
185	    } else if (ty == TOK_LPAREN) {
186	        parse_pos++;
187	        left = parse_node(0);
188	        if (parse_err) return 0;
189	        if (tok_type[parse_pos] != TOK_RPAREN) {
190	            parse_err = 1;
191	            return 0;
192	        }
193	        parse_pos++;
194	    } else if (ty == TOK_QLED) {
195	        int n = ast_new();
196	        node_type[n] = NODE_QLED;
197	        left = n;
198	        parse_pos++;
199	    } else if (ty == TOK_QSW) {
200	        int n = ast_new();
201	        node_type[n] = NODE_QSW;
202	        left = n;
203	        parse_pos++;
204	    } else if (ty == TOK_STRING) {
205	        if (tok_type[parse_pos + 1] == TOK_QSVO) {
206	            // String as identifier for qsvo coupling: 'NAME' qsvo AP
207	            int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
208	            if (sym_idx < 0) { parse_err = 1; return 0; }
209	            left = ast_ident(sym_idx);
210	        } else {
211	            // Character vector literal: 'hello' -> char vector
212	            int start = tok_val[parse_pos];
213	            int end = start;
214	            while (parse_line[end] && parse_line[end] != 39) end++;
215	            int len = end - start;
216	            int aidx = arr_vector(len);
217	            if (aidx < 0) { parse_err = 1; return 0; }
218	            arr_set_type(aidx, ARR_CHAR);
219	            int ci = 0;
220	            while (ci < len) {
221	                arr_set(aidx, ci, parse_line[start + ci]);
222	                ci++;
223	            }
224	            left = ast_vec(aidx);
225	        }
226	        parse_pos++;
227	    } else if (ty == TOK_IDENT) {
228	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
229	        if (sym_idx < 0) { parse_err = 1; return 0; }
230	        parse_pos++;
231	        // Check for monadic function call
232	        int fi = fn_lookup(sym_idx);
233	        if (fi >= 0 && fn_left_sym[fi] < 0 && can_start_expr(parse_pos)) {
234	            // Monadic user function call: FN expr
235	            int arg = parse_node(0);
236	            if (parse_err) return 0;
237	            int nd = ast_new();
238	            node_type[nd] = NODE_FNCALL;
239	            node_val[nd] = fi;
240	            node_right[nd] = arg;
241	            left = nd;
242	        } else if (tok_type[parse_pos] == TOK_LBRAK) {
243	            // IDENT[expr] -- shared variable indexed read
244	            parse_pos++;
245	            int idx_expr = parse_node(0);
246	            if (parse_err) return 0;
247	            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
248	            parse_pos++;
249	            int nd = ast_new();
250	            node_type[nd] = NODE_SVO_READ;
251	            node_val[nd] = sym_idx;
252	            node_right[nd] = idx_expr;
253	            left = nd;
254	        } else {
255	            left = ast_ident(sym_idx);
256	        }
257	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
258	        // Reduce operator: +/ -/ */ (op followed by slash)
259	        int op = ty;
260	        parse_pos = parse_pos + 2;
261	        int operand = parse_node(0);
262	        if (parse_err) return 0;
263	        left = ast_reduce(op, operand);
264	    } else if (ty == TOK_RES && (tok_val[parse_pos] == RES_CEIL || tok_val[parse_pos] == RES_FLOOR) && tok_type[parse_pos + 1] == TOK_SLASH) {
265	        // Reduce with ceil/ or floor/ (max-reduce, min-reduce)
266	        int op = (tok_val[parse_pos] == RES_CEIL) ? TOK_CEIL : TOK_FLOOR;
267	        parse_pos = parse_pos + 2;
268	        int operand = parse_node(0);
269	        if (parse_err) return 0;
270	        left = ast_reduce(op, operand);
271	    } else if (ty == TOK_RES) {
272	        // Monadic primitive function (e.g. iota expr)
273	        int res_id = tok_val[parse_pos];
274	        parse_pos++;
275	        int operand = parse_node(0);
276	        if (parse_err) return 0;
277	        left = ast_monad(res_id, operand);
278	    } else if (ty == TOK_MINUS) {
279	        // Monadic negate: applies to entire right expression (APL rule)
280	        parse_pos++;
281	        int operand = parse_node(0);
282	        if (parse_err) return 0;
283	        left = ast_neg(operand);
284	    } else {
285	        parse_err = 1;
286	        return 0;
287	    }
288	
289	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
290	
291	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
292	        int op = tok_type[parse_pos];
293	        parse_pos++;
294	        int right = parse_node(0);
295	        if (parse_err) return 0;
296	        return ast_binop(op, left, right);
297	    }
298	
299	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
300	        int res_id = tok_val[parse_pos];
301	        parse_pos++;
302	        int right = parse_node(0);
303	        if (parse_err) return 0;
304	        return ast_dyad(res_id, left, right);
305	    }
306	
307	    // Shared variable offer: 'NAME' qsvo EXPR  (or legacy: IDENT qsvo EXPR)
308	    if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
309	        int sym_idx = node_val[left];
310	        parse_pos++;
311	        int right = parse_node(0);
312	        if (parse_err) return 0;
313	        int n = ast_new();
314	        node_type[n] = NODE_QSVO;
315	        node_val[n] = sym_idx;
316	        node_right[n] = right;
317	        return n;
318	    }
319	
320	    // Dyadic user function call: expr FN expr
321	    if (mode == 0 && tok_type[parse_pos] == TOK_IDENT) {
322	        int dsym = sym_lookup(parse_line, tok_val[parse_pos]);
323	        if (dsym >= 0) {
324	            int dfi = fn_lookup(dsym);
325	            if (dfi >= 0 && fn_left_sym[dfi] >= 0) {
326	                parse_pos++;
327	                int right = parse_node(0);
328	                if (parse_err) return 0;
329	                int nd = ast_new();
330	                node_type[nd] = NODE_FNCALL;
331	                node_val[nd] = dfi;
332	                node_left[nd] = left;
333	                node_right[nd] = right;
334	                return nd;
335	            }
336	        }
337	    }
338	
339	    return left;
340	}
341	
342	// Parse the token stream. Returns root node index, or -1 on error.
343	// line is needed for identifier name resolution into the symbol table.
344	int parse(char *line) {
345	    node_count = 0;
346	    parse_pos = 0;
347	    parse_err = 0;
348	    parse_line = line;
349	
350	    // Check for qled assignment: qled <- expr
351	    if (tok_type[0] == TOK_QLED && tok_type[1] == TOK_ASSIGN) {
352	        parse_pos = 2;
353	        int expr = parse_node(0);
354	        if (parse_err) return -1;
355	        if (tok_type[parse_pos] != TOK_EOL) return -1;
356	        int n = ast_new();
357	        node_type[n] = NODE_QLED_ASSIGN;
358	        node_right[n] = expr;
359	        return n;
360	    }
361	
362	    // Check for qsw assignment: qsw is read-only, reject with SYNTAX ERROR
363	    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
364	        return -1;
365	    }
366	
367	    // Check for quad output: [] <- expr (IBM 5100 convention)
368	    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
369	        parse_pos = 2;
370	        int expr = parse_node(0);
371	        if (parse_err) return -1;
372	        if (tok_type[parse_pos] != TOK_EOL) return -1;
373	        int n = ast_new();
374	        node_type[n] = NODE_QOUT;
375	        node_right[n] = expr;
376	        return n;
377	    }
378	
379	    // Check for shared variable indexed write: IDENT[expr] <- expr
380	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
381	        int sym_idx = sym_lookup(line, tok_val[0]);
382	        if (sym_idx < 0) { return -1; }
383	        parse_pos = 2;
384	        int idx_expr = parse_node(0);
385	        if (parse_err) return -1;
386	        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
387	        parse_pos++;
388	        if (tok_type[parse_pos] == TOK_ASSIGN) {
389	            // IDENT[expr] <- expr (indexed write)
390	            parse_pos++;
391	            int val_expr = parse_node(0);
392	            if (parse_err) return -1;
393	            if (tok_type[parse_pos] != TOK_EOL) return -1;
394	            int n = ast_new();
395	            node_type[n] = NODE_SVO_WRITE;
396	            node_val[n] = sym_idx;
397	            node_left[n] = idx_expr;
398	            node_right[n] = val_expr;
399	            return n;
400	        }
401	        if (tok_type[parse_pos] != TOK_EOL) {
402	            // IDENT[expr] followed by more (could be in expression context)
403	            // For now, only standalone read supported at top level
404	            // Fall through to expression parsing below
405	            parse_pos = 0;
406	            node_count = 0;
407	            parse_err = 0;
408	        } else {
409	            // IDENT[expr] standalone read
410	            int n = ast_new();
411	            node_type[n] = NODE_SVO_READ;
412	            node_val[n] = sym_idx;
413	            node_right[n] = idx_expr;
414	            return n;
415	        }
416	    }
417	
418	    // Check for goto: goto expr  or  goto (expr)/LABEL
419	    if (tok_type[0] == TOK_GOTO) {
420	        parse_pos = 1;
421	        if (tok_type[1] == TOK_LPAREN) {
422	            // Conditional: goto (expr)/TARGET
423	            parse_pos = 2;
424	            int cond = parse_node(0);
425	            if (parse_err) return -1;
426	            if (tok_type[parse_pos] != TOK_RPAREN) return -1;
427	            parse_pos++;
428	            if (tok_type[parse_pos] != TOK_SLASH) return -1;
429	            parse_pos++;
430	            int target = parse_node(0);
431	            if (parse_err) return -1;
432	            if (tok_type[parse_pos] != TOK_EOL) return -1;
433	            int n = ast_new();
434	            node_type[n] = NODE_CGOTO;
435	            node_left[n] = cond;
436	            node_right[n] = target;
437	            return n;
438	        }
439	        // Unconditional: goto expr
440	        int target = parse_node(0);
441	        if (parse_err) return -1;
442	        if (tok_type[parse_pos] != TOK_EOL) return -1;
443	        int n = ast_new();
444	        node_type[n] = NODE_GOTO;
445	        node_right[n] = target;
446	        return n;
447	    }
448	
449	    // Check for assignment: IDENT <- expr
450	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
451	        int sym_idx = sym_lookup(line, tok_val[0]);
452	        if (sym_idx < 0) { return -1; }
453	        parse_pos = 2;
454	        int expr = parse_node(0);
455	        if (parse_err) return -1;
456	        if (tok_type[parse_pos] != TOK_EOL) return -1;
457	        return ast_assign(sym_idx, expr);
458	    }
459	
460	    int root = parse_node(0);
461	
462	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
463	        parse_err = 1;
464	    }
465	
466	    if (parse_err) return -1;
467	    return root;
468	}
469	
470	// Debug: dump AST with full parenthesization
471	void ast_dump(int n) {
472	    if (n < 0 || n >= node_count) return;
473	
474	    int ty = node_type[n];
475	    if (ty == NODE_NUM) {
476	        print_int(node_val[n]);
477	    } else if (ty == NODE_BINOP) {
478	        putchar(40);
479	        ast_dump(node_left[n]);
480	        putchar(32);
481	        if (node_val[n] == TOK_PLUS)  putchar(43);
482	        if (node_val[n] == TOK_MINUS) putchar(45);
483	        if (node_val[n] == TOK_STAR)  putchar(42);
484	        if (node_val[n] == TOK_SLASH) putchar(47);
485	        putchar(32);
486	        ast_dump(node_right[n]);
487	        putchar(41);
488	    } else if (ty == NODE_NEG) {
489	        putchar(40);
490	        putchar(45);
491	        ast_dump(node_right[n]);
492	        putchar(41);
493	    }
494	}
