1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH, 4=RANK, 5=WS FULL
9	int eval_err;
10	
11	// Branch target: -1=no branch, 0=exit, >0=line number (1-based)
12	int branch_target;
13	
14	// Shadow register for LED D2 (0xFF0000 is write-only for LEDs)
15	// Stores the user-visible value (1=on, 0=off), not the raw active-low bit
16	int qled_shadow;
17	
18	// ---- Call stack for user function recursion ----
19	
20	// Save AST state per call frame (CALL_MAX * AST_MAX = 8 * 64 = 512)
21	int save_ntype[512];
22	int save_nval[512];
23	int save_nleft[512];
24	int save_nright[512];
25	int save_ncount[CALL_MAX];
26	
27	// Save token state per call frame (CALL_MAX * TOK_MAX = 512)
28	int save_ttype[512];
29	int save_tval[512];
30	int save_tpos[512];
31	int save_tcount[CALL_MAX];
32	
33	// Save branch target per call frame
34	int save_btarget[CALL_MAX];
35	
36	// Save local variables per call frame (result, right, left = 3 per frame)
37	int save_lval[24];   // CALL_MAX * 3
38	int save_lset[24];   // CALL_MAX * 3
39	
40	int call_depth;
41	
42	// ---- Print array result (used for quad output in function bodies) ----
43	
44	void print_array(int result) {
45	    int rank = arr_rank(result);
46	
47	    // Character arrays: print as string
48	    if (arr_type(result) == ARR_CHAR) {
49	        int sz = arr_size(result);
50	        int j = 0;
51	        while (j < sz) {
52	            putchar(arr_get(result, j));
53	            j++;
54	        }
55	        putchar(10);
56	        return;
57	    }
58	
59	    if (rank == 0) {
60	        io_print("  ");
61	        print_int(arr_get(result, 0));
62	        putchar(10);
63	    } else if (rank == 1) {
64	        int sz = arr_dim0(result);
65	        int maxw = 1;
66	        int j = 0;
67	        while (j < sz) {
68	            int w = num_width(arr_get(result, j));
69	            if (w > maxw) maxw = w;
70	            j++;
71	        }
72	        j = 0;
73	        while (j < sz) {
74	            if (j == 0) putchar(32);
75	            print_int_rj(arr_get(result, j), maxw);
76	            if (j + 1 < sz) putchar(32);
77	            j++;
78	        }
