                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Scalar op vector
        if (lrk == 0 && rrk == 1) {
            int la = arr_get(lv, 0);
            int rsz = arr_size(rv);
            int r = arr_vector(rsz);
            if (r < 0) { eval_err = 5; return -1; }
            int i = 0;
            while (i < rsz) {
                int val = eval_binop_scalar(op, la, arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Vector op scalar
        if (lrk == 1 && rrk == 0) {
            int ra = arr_get(rv, 0);
            int lsz = arr_size(lv);
            int r = arr_vector(lsz);
            if (r < 0) { eval_err = 5; return -1; }
            int i = 0;
            while (i < lsz) {
                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Matrix op matrix: must match shape
        if (lrk == 2 && rrk == 2) {
            if (arr_dim0(lv) != arr_dim0(rv) || arr_dim1(lv) != arr_dim1(rv)) {
                eval_err = 3; return -1;
            }
            int d0 = arr_dim0(lv);
            int d1 = arr_dim1(lv);
            int r = arr_new(2, d0, d1);
            if (r < 0) { eval_err = 5; return -1; }
            int sz = d0 * d1;
            int i = 0;
            while (i < sz) {
                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Scalar op matrix
        if (lrk == 0 && rrk == 2) {
            int la = arr_get(lv, 0);
            int d0 = arr_dim0(rv);
            int d1 = arr_dim1(rv);
            int r = arr_new(2, d0, d1);
            if (r < 0) { eval_err = 5; return -1; }
            int sz = d0 * d1;
            int i = 0;
            while (i < sz) {
                int val = eval_binop_scalar(op, la, arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Matrix op scalar
        if (lrk == 2 && rrk == 0) {
            int ra = arr_get(rv, 0);
            int d0 = arr_dim0(lv);
            int d1 = arr_dim1(lv);
            int r = arr_new(2, d0, d1);
            if (r < 0) { eval_err = 5; return -1; }
            int sz = d0 * d1;
